/**
 * Handler 4: Content Dedup Scanner
 *
 * Detects overlapping content across loaded instruction files.
 * Reports file pairs with most shared lines and estimated token waste.
 */

import { logHook } from '../lib/common.js';
import { readFileSync } from 'node:fs';
import { basename } from 'node:path';
import type { LoadedFile } from './types.js';

const HOOK_NAME = 'instructions-loaded/content-dedup';
const DEDUP_MIN_LINE_LENGTH = 30;
const DEDUP_MIN_MATCHES = 2;

export function contentDedupScanner(filesLoaded: LoadedFile[]): string | null {
  const lineToFiles = new Map<string, Set<string>>();

  for (const f of filesLoaded) {
    try {
      const content = readFileSync(f.path, 'utf8');
      const lines = content.split('\n')
        .map(l => l.trim())
        .filter(l => l.length >= DEDUP_MIN_LINE_LENGTH && !l.startsWith('#') && !l.startsWith('|'));

      const name = basename(f.path);
      for (const line of lines) {
        if (!lineToFiles.has(line)) lineToFiles.set(line, new Set());
        lineToFiles.get(line)!.add(name);
      }
    } catch {
      // Skip unreadable
    }
  }

  const duplicates: Array<{ line: string; files: string[] }> = [];
  for (const [line, files] of lineToFiles) {
    if (files.size >= 2) {
      duplicates.push({ line: line.slice(0, 60), files: [...files] });
    }
  }

  if (duplicates.length < DEDUP_MIN_MATCHES) return null;

  const pairCounts = new Map<string, number>();
  for (const dup of duplicates) {
    const sorted = [...dup.files].sort();
    for (let i = 0; i < sorted.length; i++) {
      for (let j = i + 1; j < sorted.length; j++) {
        const key = `${sorted[i]} <> ${sorted[j]}`;
        pairCounts.set(key, (pairCounts.get(key) || 0) + 1);
      }
    }
  }

  const topPairs = [...pairCounts.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3);

  const wastedTokens = duplicates.reduce((sum, d) => sum + Math.ceil(d.line.length / 4), 0);

  logHook(HOOK_NAME, `Dedup scanner: ${duplicates.length} duplicated lines (~${wastedTokens} tokens wasted)`);

  const parts = [`[Content Overlap] ${duplicates.length} duplicated lines across instruction files (~${wastedTokens} tokens):`];
  for (const [pair, count] of topPairs) {
    parts.push(`  ${pair}: ${count} shared lines`);
  }

  return parts.join('\n');
}
